function formatLegalText(text) {
  const container = document.createElement("div");
  const blocks = text.split(/\n\s*\n/);

  blocks.forEach((block) => {
    const trimmed = block.trim();
    if (!trimmed) return;

    const isMainSection = /^\d+\.\s/.test(trimmed);

    if (isMainSection) {
      const heading = document.createElement("div");
      heading.className = "numbered-title";
      heading.textContent = trimmed;
      container.appendChild(heading);
    } else {
      const p = document.createElement("p");
      p.textContent = trimmed;
      container.appendChild(p);
    }
  });

  return container;
}

function setLanguage(lang) {
  const data = legalContent[lang];

  document.documentElement.lang = lang;
  document.title = `Pompeian Novena - ${data.pageTitle}`;
  document.getElementById("pageTitle").textContent = data.pageTitle;
  document.getElementById("pageSubtitle").textContent = data.pageSubtitle;
  document.getElementById("privacyTitle").textContent = data.privacyTitle;
  document.getElementById("termsTitle").textContent = data.termsTitle;

  const privacyEl = document.getElementById("privacyContent");
  const termsEl = document.getElementById("termsContent");

  privacyEl.innerHTML = "";
  termsEl.innerHTML = "";

  privacyEl.appendChild(formatLegalText(data.privacyContent));
  termsEl.appendChild(formatLegalText(data.termsContent));

  document.getElementById("privacyTab").textContent =
    lang === "pl" ? "Polityka prywatności" : "Privacy Policy";
  document.getElementById("termsTab").textContent =
    lang === "pl" ? "Regulamin" : "Terms of Use";

  document
    .getElementById("langPlBtn")
    .classList.toggle("active", lang === "pl");
  document
    .getElementById("langEnBtn")
    .classList.toggle("active", lang === "en");

  localStorage.setItem("legal_lang", lang);
}

document
  .getElementById("langPlBtn")
  .addEventListener("click", () => setLanguage("pl"));
document
  .getElementById("langEnBtn")
  .addEventListener("click", () => setLanguage("en"));

const savedLang = localStorage.getItem("legal_lang");
setLanguage(savedLang === "pl" ? "pl" : "en");
